(function($){'use strict';function initCustomerSelect(selector,type = 'customers'){const $select = $(selector);if($select.hasClass('select2-hidden-accessible')){$select.select2('destroy');}const config ={ajax:{url:'/api/search',dataType:'json',delay:250,data:function(params){return{q:params.term || '',type:type,page:params.page || 1};},processResults:function(data){return{results:data.results.map(c =>({id:c.id,text:c.name || c.text,name:c.name,phone:c.phone,email:c.email,customer_type:c.customer_type,balance_aed:c.balance_aed || 0})),pagination:{more:data.has_more || false}};},cache:true},placeholder:type === 'suppliers' ? 'ابحث عن مورد...':'ابحث عن زبون...',allowClear:true,minimumInputLength:0,dir:'rtl',width:'100%',templateResult:formatCustomer,templateSelection:formatCustomerSelection,escapeMarkup:m => m};$select.select2(config);addQuickAddButton($select,type);}function formatCustomer(c){if(c.loading)return 'جاري البحث...';if(!c.id)return c.text;const typeIcon = c.customer_type === 'VIP' ? '⭐':c.customer_type === 'Merchant' ? '🏪':'👤';const balance = c.balance_aed || 0;const balanceClass = balance > 0 ? 'text-danger':balance < 0 ? 'text-success':'text-muted';return ` <div class="select2-result-item" style="padding:5px;"> <div class="d-flex justify-content-between"> <div> <strong>${typeIcon}${c.text}</strong> ${c.phone ? `<br><small class="text-muted"><i class="fas fa-phone fa-xs"></i> ${c.phone}</small>`:''}</div> <small class="${balanceClass}"> ${balance.toLocaleString('ar-AE',{minimumFractionDigits:0})}AED </small> </div> </div> `;}function formatCustomerSelection(c){const typeIcon = c.customer_type === 'VIP' ? '⭐':c.customer_type === 'Merchant' ? '🏪':'👤';return c.id ? `${typeIcon}${c.text}`:c.text;}function initProductSelect(selector){const $select = $(selector);if($select.hasClass('select2-hidden-accessible')){$select.select2('destroy');}const config ={ajax:{url:'/api/search',dataType:'json',delay:250,data:function(params){return{q:params.term || '',type:'products',page:params.page || 1};},processResults:function(data){return{results:data.results.map(p =>({id:p.id,text:p.name || p.text,sku:p.sku,price:p.default_price || p.unit_price || 0,stock:p.current_stock || 0,cost:p.cost_price || 0})),pagination:{more:data.has_more || false}};},cache:true},placeholder:'ابحث عن منتج...',allowClear:true,minimumInputLength:0,dir:'rtl',width:'100%',templateResult:formatProduct,templateSelection:formatProductSelection,escapeMarkup:m => m};$select.select2(config);addQuickAddButton($select,'products');}function formatProduct(p){if(p.loading)return 'جاري البحث...';if(!p.id)return p.text;const stockIcon = p.stock > 0 ? '✅':'❌';const stockClass = p.stock > 0 ? 'text-success':'text-danger';return ` <div class="select2-result-item" style="padding:5px;"> <div class="d-flex justify-content-between"> <div> <strong>📦 ${p.text}</strong> <br><small class="text-muted">SKU:${p.sku || '-'}</small> </div> <div class="text-left"> <small><strong>${p.price.toLocaleString('ar-AE')}AED</strong></small> <br><small class="${stockClass}">${stockIcon}${p.stock}</small> </div> </div> </div> `;}function formatProductSelection(p){return p.id ? `📦 ${p.text}`:p.text;}function initWarehouseSelect(selector){const $select = $(selector);if($select.hasClass('select2-hidden-accessible')){$select.select2('destroy');}$select.select2({placeholder:'اختر المستودع...',allowClear:true,dir:'rtl',width:'100%'});addQuickAddButton($select,'warehouses');}function addQuickAddButton($select,type){const $container = $select.next('.select2-container');if($container.next('.quick-add-btn').length > 0){return;}const configs ={'customers':{url:'/customers/create',text:'➕ زبون جديد',color:'success'},'suppliers':{url:'/customers/create?type=supplier',text:'➕ مورد جديد',color:'info'},'products':{url:'/products/create',text:'➕ منتج جديد',color:'primary'},'warehouses':{url:'/warehouse/create-warehouse',text:'➕ مستودع جديد',color:'warning'}};const conf = configs[type];if(!conf)return;const $btn = $(` <button type="button" class="btn btn-${conf.color}btn-sm btn-block quick-add-btn mt-1"> ${conf.text}</button> `);$btn.on('click',function(e){e.preventDefault();window.open(conf.url,'_blank','width=900,height=700');});$container.after($btn);}function initAllSelectors(){$('select[name="customer_id"],select[name="client_id"],.customer-select').each(function(){if(!$(this).hasClass('select2-hidden-accessible')){initCustomerSelect(this,'customers');}});$('select[name="supplier_id"],.supplier-select').each(function(){if(!$(this).hasClass('select2-hidden-accessible')){initCustomerSelect(this,'suppliers');}});$('select[name="product_id"],.product-select').each(function(){if(!$(this).hasClass('select2-hidden-accessible')){initProductSelect(this);}});$('select[name="warehouse_id"],.warehouse-select').each(function(){if(!$(this).hasClass('select2-hidden-accessible')){initWarehouseSelect(this);}});}$(document).ready(function(){initAllSelectors();});$(document).on('DOMNodeInserted',function(e){const $target = $(e.target);if($target.is('select')|| $target.find('select').length){setTimeout(initAllSelectors,100);}});window.SmartSelectors ={initCustomers:function(sel){initCustomerSelect(sel,'customers');},initSuppliers:function(sel){initCustomerSelect(sel,'suppliers');},initProducts:function(sel){initProductSelect(sel);},initWarehouses:function(sel){initWarehouseSelect(sel);},initAll:initAllSelectors};})(jQuery);